-- BLOCO 1 (parte 5/6) — Revisão linguística pílulas PV (4 variants pt-BR)

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Sem crise. Só uma abertura sem destino ainda.", "tension_label": "Dentro ↔ Fora"}, "m2": {"scene": "Carolina, 37, largou o trabalho de enfermeira há três meses. O burnout era total — turnos de doze horas, esgotamento emocional, a sensação de que algo essencial nela estava sendo drenado. Economizou o que pôde em cinco anos, e isso está comprando tempo. Mas a família dela está cética. A mãe chamou de 'irresponsável'. A irmã perguntou se ela estava tendo um colapso. Tem fôlego pra mais seis meses, talvez, antes de precisar trabalhar de novo. Algo dentro disse pare, e ela parou. Acorda sentindo que algo nela está escutando. Tem lido, feito caminhadas longas, voluntariado numa ONG de alfabetização. Descobriu que consegue estar em silêncio. As amigas continuam perguntando: 'E aí, qual o próximo passo? — você precisa de um plano.' Ela notou que quando perguntam com preocupação, ela fecha. Quando perguntam com curiosidade, ela abre. É fim de tarde de quarta. Uma ex-colega de enfermagem mandou mensagem: 'Ouvi dizer que você saiu. Café? Estamos contratando na clínica nova — pagamento melhor, mesma exaustão.'", "question": "O que Carolina está procurando agora? E se aceitar esse café, pra onde vai estar indo — ou de onde fugindo?"}, "m4": {"question": "Algo te trouxe até aqui — mesmo que você não consiga nomear. Agora, isso parece mais curiosidade ou mais inquietação?", "instruction": "Uma palavra ou uma frase. Não explique — só deixe a palavra existir."}, "m3_1": {"context": "", "question": "Quando algo dentro abre sem razão clara ou crise, você costuma se mover pra explorar (não dar nome ainda, manter a curiosidade) ou pra estabilizar (achar um nome, mover pra ação)?", "pole_left": "Explorar", "pole_right": "Estabilizar"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Fico sem dar nome ainda — descubro que tipo de escuta essa abertura pede.", "followup": "O que aconteceria se você se desse permissão pra ainda não entender?", "followup_type": "question"}, {"key": "B", "text": "Falo mesmo assim.", "followup": "Pra quem, e o que você espera que ela faça com o que você contar?", "followup_type": "question"}, {"key": "C", "text": "Ajo como se entendesse — me movo em direção a algo que talvez esteja chamando.", "followup": "O que você está testando ao se mover antes de entender?", "followup_type": "question"}, {"key": "D", "text": "Procuro o que talvez esteja evitando — essa abertura é real, ou estou fugindo de algo?", "followup": "O que precisaria pra você confiar na abertura em vez de interrogá-la?", "followup_type": "question"}], "scenario": "Você sente algo se mexendo, mas ainda sem nome claro. As pessoas em volta não parecem notar. Ou talvez notam. E agora você está numa escolha: isso fica dentro, ou se move pra fora?"}, "m3_3": {"q1": "Lembre de uma vez em que algo dentro de você abriu ou se mexeu sem uma crise forçando. Quais eram as circunstâncias? O que estava abrindo?", "q2": "Do que você precisou — ou o que você tinha — que te permitiu permanecer com aquilo em vez de fechar ou correr pra resolver?", "scoring_note": "", "q_transversal": "Quando você ficou com aquilo — você tinha um jeito de lidar, ou só foi indo?"}}$rdwth_final$::jsonb
WHERE id = 'd96cfcd1-f8ee-4a22-8ea9-de736ed22172';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Algo se mexeu. Ainda não tenho linguagem. Mas estou escutando.", "tension_label": "Dentro ↔ Fora"}, "m2": {"scene": "Roberto, 51, está na mesma carreira há 28 anos. Sem crise. Ainda competente. Ainda necessário. Mas há seis meses, algo começou a coçar. Não uma queixa. Não vontade de fugir. Só uma coceira que diz que tem outra coisa. Não contou pra ninguém, exceto pra esposa. Em reuniões de equipe, sua mente está em outro lugar. Começou a frequentar eventos fora da área. Está lendo diferente. Está fazendo pros filhos adultos perguntas sobre o que eles sabem sobre si mesmos que ele não sabia na idade deles. Não está procurando emprego. Não está deprimido. Está procurando. Mas pelo quê, não consegue articular. É segunda de manhã. O chefe acabou de designar ele pra liderar o próximo grande projeto — daqueles que o teriam empolgado dois anos atrás.", "question": "Pelo quê Roberto está disponível agora? E o que está protegendo ao não nomear ainda?"}, "m4": {"question": "Conforme você passou pelas perguntas, a abertura dentro de você ficou mais clara ou mais turva? O que isso te diz sobre o que a abertura é?", "instruction": "Uma palavra basta. Ou uma frase. Diga o que está se abrindo em você, mesmo que impreciso."}, "m3_1": {"context": "", "question": "Quando sente algo se mexendo mas ainda não entende, é mais inclinado a compartilhar o que está vivendo (tornar real ao nomear com outros) ou a manter privado (proteger até entender por si mesmo)?", "pole_left": "Compartilhar", "pole_right": "Manter privado"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Nomeio honestamente — corro o risco de ser conhecido.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "B", "text": "Pauso antes de responder — tomo tempo pra entender o que a pergunta dela está de fato pedindo de mim.", "followup": "O que significaria compartilhar agora vs. proteger um pouco mais?", "followup_type": "question"}, {"key": "C", "text": "Nomeio mas enquadro como temporário ou provisório — 'estou explorando algo, mas nada decidido'.", "followup": "O que você está protegendo ao manter a porta entreaberta?", "followup_type": "question"}, {"key": "D", "text": "Pergunto por que ela notou — viro a atenção dela pra ela mesma em vez de pra meu interior.", "followup": "Você está protegendo a abertura em si, ou se protegendo do julgamento dela?", "followup_type": "question"}], "scenario": "Algo está se mexendo dentro de você. Não é alto, mas é distinto. E agora alguém de fora perguntou diretamente sobre isso — uma pergunta que exige que você nomeie ou negue. Você poderia ficar opaco. Poderia ser honesto. Poderia responder pela metade. Está na limite."}, "m3_3": {"q1": "Lembre de uma vez em que se sentiu disponível pra algo que ainda não conseguia nomear. Quando foi isso, e como essa disponibilidade era no corpo?", "q2": "Você falou disso pra alguém? Se sim, o que tornou seguro? Se não, o que protegeu?", "scoring_note": "", "q_transversal": "Quando você falou — ou escolheu não falar — a conversa honrou o que estava acontecendo dentro de você?"}}$rdwth_final$::jsonb
WHERE id = '8d497968-c00c-4f21-9444-15be81d7ab63';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Estou disponível. Não por decisão. Por algo que não consigo nomear bem.", "tension_label": "Dentro ↔ Fora"}, "m2": {"scene": "Camila, 29, está numa relação que funciona. O trabalho é sólido. Tem comunidade. Mas algo nos últimos oito meses abriu. Não em crise. Em curiosidade. Tem sido atraída por perguntas que nunca tinha feito. Sobre o que ela de fato quer, não o que deveria querer. Sobre por que faz as escolhas que faz. Começou terapia — não porque algo está quebrado, mas porque algo está acordando. A namorada notou. Os colegas notaram. Ela parece presente mas também em outro lugar. Continua comprometida com tudo. Mas também está disponível pra algo que não consegue nomear. É sexta à noite. Uma mentora que ela respeita acabou de procurar perguntando se ela teria interesse em explorar um programa sabático.", "question": "O que abriu em Camila, e o que acontece se ela disser sim a essa oportunidade — ou se disser não?"}, "m4": {"question": "Agora — você está mais inclinado a entender o que está se mexendo, ou pra proteger isso de ser entendido cedo demais?", "instruction": "Uma frase. Qual lado move mais forte — e do que você teria medo se deixasse o outro vencer?"}, "m3_1": {"context": "", "question": "Em momentos em que você está disponível pra algo novo mas sem saber o quê, prefere abrir (dizer sim, ir em direção) ou esperar (observar, não forçar nada)?", "pole_left": "Abrir", "pole_right": "Esperar"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Aceito a oportunidade — mas pergunto a ela o que está tentando me ensinar antes de decidir.", "followup": "O que a oportunidade te ensinaria se você ficasse curioso em vez de comprometido?", "followup_type": "question"}, {"key": "B", "text": "Espero — não estou pronto pra mexer em algo que não entendo.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "C", "text": "Procuro uma versão menor dessa oportunidade — algo que me deixe explorar sem compromisso total.", "followup": "O que precisaria pra você se comprometer plenamente?", "followup_type": "question"}, {"key": "D", "text": "Falo com pessoas em quem confio antes de decidir — uso a reflexão delas pra clarear o que está acontecendo dentro.", "followup": "O que a clareza delas te dá que ficar sozinho não dá?", "followup_type": "question"}], "scenario": "Uma oportunidade chegou que parece chamar pra coisa nova que está abrindo. Você ainda não entende plenamente a abertura. Poderia aceitar a oportunidade e deixar ela te ensinar o que a abertura significa. Esperar até estar mais claro. Buscar algo menor que pareça mais seguro. Descartar como coincidência e ficar parado."}, "m3_3": {"q1": "Lembre de um momento em que estava no meio de uma abertura — algo se mexendo mas ainda não formado. O que estava acontecendo na sua vida, e o que você fazia com a incerteza?", "q2": "O que te permitiu ficar paciente com isso? Tinha uma pessoa, uma prática, uma fé, uma circunstância que ajudou a não apressar?", "scoring_note": "", "q_transversal": "Permanecendo na incerteza — como você soube que estava acolhendo o que veio, em vez de só boiando?"}}$rdwth_final$::jsonb
WHERE id = '556818c0-af9b-40d8-af38-e438718faac3';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "A abertura é real. O chão ainda não chegou. Estou esperando no meio.", "tension_label": "Dentro ↔ Fora"}, "m2": {"scene": "Felipe, 44, dá aula no ensino médio. Faz isso há dezessete anos. Avaliações sólidas, salário estável, conhece o ofício. Mas começando em setembro passado, algo se mexeu por dentro. Não um colapso. Uma abertura. Está mais atento às perguntas dos alunos, menos apegado às respostas do currículo. Está lendo livros de filosofia à noite. Está sentando com silêncio em jeitos que parecem novos. Nada externo mudou. O casamento é o mesmo. A hipoteca é a mesma. Mas o dentro dele ficou mais disponível — pra quê, ele não tem certeza. A coordenadora acabou de pedir que ele lidere o redesenho do currículo do ano que vem. A esposa perguntou se ele está feliz. Nenhuma das duas perguntas parece ter resposta clara.", "question": "O que está acontecendo dentro de Felipe, e o que ele arrisca perder se parar de escutar?"}, "m4": {"question": "Se a coisa que está abrindo em você tivesse uma pergunta — não uma resposta, só uma pergunta — qual ela estaria fazendo?", "instruction": "Escreva a pergunta em si — não uma resposta a ela. Uma frase basta."}, "m3_1": {"context": "", "question": "Quando algo abre em você sem pressão de fora, você confia (assume que algo verdadeiro está tentando emergir) ou questiona (se pergunta se está evitando algo, ou se é temporário)?", "pole_left": "Confiar", "pole_right": "Questionar"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Vou em frente — ajo na abertura, vejo aonde dá.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "B", "text": "Volto — retorno pro estável, nomeio isso como um momento que passou.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "C", "text": "Fico no meio mais tempo — resisto a escolher, fico disponível e escutando.", "followup": "Por quanto tempo consegue ficar aqui, e o que custa fazer isso?", "followup_type": "question"}, {"key": "D", "text": "Dou passos pequenos e visíveis — crio estruturas que honram a abertura sem perder o chão.", "followup": "Que tipo de estrutura te deixaria ficar aberto sem perder o eixo?", "followup_type": "question"}], "scenario": "Você está no meio de algo abrindo. A abertura não vem com instruções. E agora encara uma escolha: ficar no meio e continuar escutando, ou se mover pra uma das bordas — pra trás, pro estável, ou pra frente, pro que está chamando."}, "m3_3": {"q1": "Descreva uma vez em que algo te chamou sem você entender plenamente o quê. O que estava te chamando, e o que você fez?", "q2": "Olhando para trás, o que te fez confiar nesse chamado o suficiente pra ir em direção (ou desconfiar o suficiente pra recuar)?", "scoring_note": "", "q_transversal": "Quando você seguiu esse chamado — o que você levou foi o suficiente pra responder ao que ele pediu?"}}$rdwth_final$::jsonb
WHERE id = '9c539d2a-3711-4787-bee7-6dc752adabf0';